# --- Utility for JWT validation ---
def jwt_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')

        if not auth_header:
            return jsonify({'message': 'Authorization header is missing!'}), 401

        try:
            # Expecting "Bearer <token>"
            token_type, token = auth_header.split(None, 1)
            if token_type.lower() != 'bearer':
                raise ValueError("Unsupported authorization type.")
        except ValueError:
            return jsonify({'message': 'Invalid Authorization header format. Expected "Bearer <token>"'}), 401
        except IndexError:
            return jsonify({'message': 'Invalid Authorization header format. Token missing.'}), 401

        try:
            # Decode the token without verification for development speed.
            # !!! WARNING: For production, you MUST verify the token with a secret/public key.
            # Example for production: jwt.decode(token, SECRET_KEY, algorithms=['HS256'])
            decoded_token = jwt.decode(token, options={"verify_signature": False})
            request.user_claims = decoded_token  # Attach claims to the request object
        except jwt.ExpiredSignatureError:
            return jsonify({'message': 'Token has expired!'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'message': 'Invalid token!'}), 401
        except Exception as e:
            return jsonify({'message': f'An unexpected error occurred during token processing: {str(e)}'}), 500

        return f(*args, **kwargs)
    return decorated_function

