    import json

    # Construct the full backend URL
    backend_full_url = f"{BACKEND_SERVICE_URL}/{subpath}"

    # Prepare headers for the backend
    headers = {
        'Content-Type': request.headers.get('Content-Type', 'application/json'),
        'X-User-Claims': json.dumps(request.user_claims) # Forward user claims
    }
    # Optionally forward other headers from the original request
    for hdr in ['Accept', 'Accept-Language', 'User-Agent']: # Add more as needed
        if hdr in request.headers:
            headers[hdr] = request.headers[hdr]


    # Prepare data for the backend (for POST, PUT, PATCH)
    data = None
    json_data = None
    if request.method in ['POST', 'PUT', 'PATCH']:
        if request.is_json:
            json_data = request.get_json()
        else:
            data = request.get_data() # Raw data for other content types

    try:
        # Make the request to the backend service
        backend_response = requests.request(
            method=request.method,
            url=backend_full_url,
            headers=headers,
            data=data,
            json=json_data,
            params=request.args, # Forward query parameters
            allow_redirects=False, # Typically gateways don't follow redirects automatically
            timeout=10 # Set a timeout for backend requests
        )

        # Reconstruct the Flask response from the backend's response
        response = jsonify(backend_response.json())
        response.status_code = backend_response.status_code
        for key, value in backend_response.headers.items():
            if key.lower() not in ['content-encoding', 'transfer-encoding', 'content-length']:
                response.headers[key] = value

        return response

    except requests.exceptions.RequestException as e:
        app.logger.error(f"Error forwarding request to backend {backend_full_url}: {e}")
        return jsonify({'message': 'Failed to connect to backend service', 'error': str(e)}), 503
